    if (HD >= 5e3) level = -2;
    if (HD >= 500) level = -1;
    if (HD <= 40) level = 0;
    if (HD <= 1) level = 1;
    if (HD <= 0.5) level = 2;
    if (HD <= 0.1) level = 3;
    if (HD <= 0.05) level = 4;
    if (HD <= 0.01) level = 5;
    if (HD <= 5e-3) level = 6;
    if (HD <= 1e-4) level = 7;
    if (HD <= 5e-5) level = 8;
    return level;
